<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Sorting Visualizer</title>
<style>
  :root {
    --bg: #1a1b26;
    --panel: #24273a;
    --accent: #7aa2f7;
    --accent2: #f7768e;
    --accent3: #9ece6a;
    --text: #c0caf5;
  }
  * { box-sizing: border-box; }
  body {
    margin: 0;
    background: var(--bg);
    color: var(--text);
    font-family: system-ui, sans-serif;
    display: flex;
    flex-direction: column;
    align-items: center;
    padding: 24px;
    min-height: 100vh;
  }
  h1 {
    font-size: 1.4rem;
    font-weight: 600;
    margin: 0 0 16px;
  }
  #controls {
    display: flex;
    gap: 10px;
    margin-bottom: 20px;
    flex-wrap: wrap;
    align-items: center;
  }
  button, select {
    background: var(--panel);
    color: var(--text);
    border: 1px solid #414868;
    padding: 8px 16px;
    border-radius: 6px;
    cursor: pointer;
    font-size: 0.9rem;
    transition: background 0.15s;
  }
  button:hover, select:hover {
    background: #2f3350;
  }
  button:disabled {
    opacity: 0.5;
    cursor: not-allowed;
  }
  label {
    font-size: 0.85rem;
    color: #8b8fa3;
    display: flex;
    align-items: center;
    gap: 6px;
  }
  #bars {
    width: 100%;
    max-width: 900px;
    height: 360px;
    background: var(--panel);
    border-radius: 10px;
    display: flex;
    align-items: flex-end;
    gap: 2px;
    padding: 10px;
    border: 1px solid #414868;
  }
  .bar {
    background: var(--accent);
    flex: 1;
    min-width: 2px;
    border-radius: 2px 2px 0 0;
    transition: height 0.08s linear;
  }
  .bar.compare { background: var(--accent2); }
  .bar.swap { background: var(--accent3); }
  #status {
    margin-top: 14px;
    font-size: 0.85rem;
    color: #8b8fa3;
    min-height: 1.2em;
  }
</style>
</head>
<body>

<h1>Sorting Algorithm Visualizer</h1>

<div id="controls">
  <label>Algorithm
    <select id="algo">
      <option value="bubble">Bubble Sort</option>
      <option value="selection">Selection Sort</option>
      <option value="insertion">Insertion Sort</option>
    </select>
  </label>
  <label>Size
    <select id="size">
      <option value="20">20</option>
      <option value="40" selected>40</option>
      <option value="80">80</option>
    </select>
  </label>
  <label>Speed
    <input type="range" id="speed" min="1" max="100" value="60">
  </label>
  <button id="sort">Sort</button>
  <button id="shuffle">Shuffle</button>
  <button id="reset">Reset</button>
</div>

<div id="bars"></div>
<div id="status"></div>

<script>
(function() {
  const barsEl = document.getElementById('bars');
  const statusEl = document.getElementById('status');
  const sortBtn = document.getElementById('sort');
  const shuffleBtn = document.getElementById('shuffle');
  const resetBtn = document.getElementById('reset');
  const algoSel = document.getElementById('algo');
  const sizeSel = document.getElementById('size');
  const speedEl = document.getElementById('speed');

  let arr = [];
  let originalArr = [];
  let animating = false;
  let animTimer = null;

  // Sort-state machine: holds whichever algorithm's step state is active.
  let sortState = null;

  function randomArray(n) {
    const a = [];
    for (let i = 0; i < n; i++) a.push(Math.floor(Math.random() * 96) + 4);
    return a;
  }

  function render(highlight) {
    highlight = highlight || {};
    barsEl.innerHTML = '';
    const max = Math.max(...arr, 1);
    for (let i = 0; i < arr.length; i++) {
      const bar = document.createElement('div');
      bar.className = 'bar';
      if (highlight.compare && highlight.compare.includes(i)) bar.className += ' compare';
      if (highlight.swap && highlight.swap.includes(i)) bar.className += ' swap';
      bar.style.height = (arr[i] / max * 100) + '%';
      bar.title = arr[i];
      barsEl.appendChild(bar);
    }
  }

  function isSorted() {
    for (let i = 1; i < arr.length; i++) {
      if (arr[i - 1] > arr[i]) return false;
    }
    return true;
  }

  // ---- Bubble sort step machine ----
  function makeBubbleState() {
    return { i: 0, j: 0, n: arr.length, done: arr.length <= 1 };
  }
  function bubbleStep(state) {
    if (state.done) return { done: true };
    const n = state.n;
    if (state.i >= n - 1) {
      state.done = true;
      return { done: true };
    }
    const j = state.j;
    const compare = [j, j + 1];
    let swap = [];
    if (arr[j] > arr[j + 1]) {
      const tmp = arr[j];
      arr[j] = arr[j + 1];
      arr[j + 1] = tmp;
      swap = [j, j + 1];
    }
    state.j++;
    if (state.j >= n - state.i - 1) {
      state.j = 0;
      state.i++;
      if (state.i >= n - 1) state.done = true;
    }
    return { done: state.done, compare, swap };
  }

  // ---- Selection sort step machine ----
  function makeSelectionState() {
    return { i: 0, j: 1, min: 0, n: arr.length, done: arr.length <= 1 };
  }
  function selectionStep(state) {
    if (state.done) return { done: true };
    const n = state.n;
    if (state.i >= n - 1) {
      state.done = true;
      return { done: true };
    }
    const compare = [state.j, state.min];
    if (arr[state.j] < arr[state.min]) {
      state.min = state.j;
    }
    state.j++;
    let swap = [];
    if (state.j >= n) {
      if (state.min !== state.i) {
        const tmp = arr[state.i];
        arr[state.i] = arr[state.min];
        arr[state.min] = tmp;
        swap = [state.i, state.min];
      }
      state.i++;
      state.j = state.i + 1;
      state.min = state.i;
      if (state.i >= n - 1) state.done = true;
    }
    return { done: state.done, compare, swap };
  }

  // ---- Insertion sort step machine ----
  function makeInsertionState() {
    return { i: 1, j: 1, n: arr.length, phase: 'compare', done: arr.length <= 1 };
  }
  function insertionStep(state) {
    if (state.done) return { done: true };
    const n = state.n;
    if (state.i >= n) {
      state.done = true;
      return { done: true };
    }
    const j = state.j;
    if (j <= 0) {
      state.i++;
      state.j = state.i;
      if (state.i >= n) {
        state.done = true;
        return { done: true };
      }
      return { done: false, compare: [], swap: [] };
    }
    const compare = [j - 1, j];
    let swap = [];
    if (arr[j - 1] > arr[j]) {
      const tmp = arr[j - 1];
      arr[j - 1] = arr[j];
      arr[j] = tmp;
      swap = [j - 1, j];
      state.j--;
    } else {
      state.i++;
      state.j = state.i;
      if (state.i >= n) state.done = true;
    }
    return { done: state.done, compare, swap };
  }

  function makeSortState() {
    const algo = algoSel.value;
    if (algo === 'selection') return { type: 'selection', s: makeSelectionState() };
    if (algo === 'insertion') return { type: 'insertion', s: makeInsertionState() };
    return { type: 'bubble', s: makeBubbleState() };
  }

  function sortStep() {
    if (arr.length <= 1) return true;
    if (!sortState) sortState = makeSortState();
    let result;
    if (sortState.type === 'selection') result = selectionStep(sortState.s);
    else if (sortState.type === 'insertion') result = insertionStep(sortState.s);
    else result = bubbleStep(sortState.s);

    render({ compare: result.compare, swap: result.swap });

    if (result.done || isSorted()) {
      sortState = null;
      render();
      return true;
    }
    return false;
  }

  function setArray(a) {
    arr = a.slice();
    sortState = null;
    render();
  }

  function stopAnimation() {
    if (animTimer) {
      clearTimeout(animTimer);
      animTimer = null;
    }
    animating = false;
    sortBtn.disabled = false;
    shuffleBtn.disabled = false;
    resetBtn.disabled = false;
  }

  function animateSort() {
    if (animating) return;
    animating = true;
    sortBtn.disabled = true;
    shuffleBtn.disabled = true;
    resetBtn.disabled = true;
    statusEl.textContent = 'Sorting...';

    function tick() {
      const done = sortStep();
      if (done) {
        stopAnimation();
        statusEl.textContent = 'Sorted!';
        return;
      }
      const speed = Number(speedEl.value);
      const delay = Math.max(1, 300 - speed * 3);
      animTimer = setTimeout(tick, delay);
    }
    tick();
  }

  sortBtn.addEventListener('click', animateSort);

  shuffleBtn.addEventListener('click', function() {
    if (animating) return;
    const n = Number(sizeSel.value);
    originalArr = randomArray(n);
    setArray(originalArr);
    statusEl.textContent = '';
  });

  resetBtn.addEventListener('click', function() {
    if (animating) return;
    if (!originalArr.length) originalArr = randomArray(Number(sizeSel.value));
    setArray(originalArr);
    statusEl.textContent = '';
  });

  sizeSel.addEventListener('change', function() {
    if (animating) return;
    originalArr = randomArray(Number(sizeSel.value));
    setArray(originalArr);
    statusEl.textContent = '';
  });

  algoSel.addEventListener('change', function() {
    sortState = null;
  });

  // init
  originalArr = randomArray(Number(sizeSel.value));
  setArray(originalArr);

  window.viz = {
    array: function() { return arr.slice(); },
    setArray: function(a) { setArray(a); },
    sortStep: function() { return sortStep(); },
    sorted: function() { return isSorted(); }
  };
})();
</script>

</body>
</html>
```
